python3 -c "
import json, subprocess

tests = [
    # Example 1: Normalize casing and rename from/to -> mapping
    {
        'name': 'Example 1: Normalize casing and rename',
        'input': {
            'pipeline': {
                'steps': [
                    {'op': 'Select', 'columns': ['id', 'price', 'category']},
                    {'op': 'rename', 'from': 'price', 'to': 'usd_price'}
                ]
            },
            'dataset': []
        },
        'expected_status': 'ok'
    },
    # Example 2: Unknown operation error
    {
        'name': 'Example 2: Unknown operation error',
        'input': {
            'pipeline': {'steps': [{'op': 'TRANSPOSE'}]},
            'dataset': []
        },
        'expected_status': 'error',
        'expected_code': 'UNKNOWN_OP'
    },
    # Example 3: Empty pipeline is valid
    {
        'name': 'Example 3: Empty pipeline is valid',
        'input': {
            'pipeline': {'steps': []},
            'dataset': []
        },
        'expected_status': 'ok'
    },
    # Test unknown top-level keys ignored
    {
        'name': 'Unknown top-level keys ignored',
        'input': {
            'pipeline': {'steps': []},
            'dataset': [],
            'unknown_key': 'should be ignored'
        },
        'expected_status': 'ok'
    },
    # Test trimming expressions
    {
        'name': 'Trim expressions',
        'input': {
            'pipeline': {'steps': [{'op': 'filter', 'where': '  qty * price  '}]},
            'dataset': []
        },
        'expected_status': 'ok',
        'expected_where': 'qty * price'
    },
    # Test renaming with mapping object
    {
        'name': 'Rename with mapping',
        'input': {
            'pipeline': {'steps': [{'op': 'rename', 'mapping': {'a': 'b', 'c': 'd'}}]},
            'dataset': []
        },
        'expected_status': 'ok'
    },
    # Test column names preserved exactly
    {
        'name': 'Column names preserved exactly',
        'input': {
            'pipeline': {'steps': [{'op': 'select', 'columns': ['  id  ', 'price']}]},
            'dataset': []
        },
        'expected_status': 'ok'
    },
    # Test missing required field
    {
        'name': 'Missing required field',
        'input': {
            'pipeline': {'steps': [{'op': 'select'}]},
            'dataset': []
        },
        'expected_status': 'error',
        'expected_code': 'MISSING_COLUMN'
    },
    # Test invalid JSON
    {
        'name': 'Invalid JSON',
        'input_raw': 'not json',
        'expected_status': 'error',
        'expected_code': 'SCHEMA_VALIDATION_FAILED'
    },
    # Test missing dataset
    {
        'name': 'Missing dataset',
        'input': {
            'pipeline': {'steps': []}
        },
        'expected_status': 'error',
        'expected_code': 'SCHEMA_VALIDATION_FAILED'
    },
    # Test dataset item not object
    {
        'name': 'Dataset item not object',
        'input': {
            'pipeline': {'steps': []},
            'dataset': ['not an object']
        },
        'expected_status': 'error',
        'expected_code': 'SCHEMA_VALIDATION_FAILED'
    },
    # Test limit n=0 (valid)
    {
        'name': 'Limit n=0 valid',
        'input': {
            'pipeline': {'steps': [{'op': 'limit', 'n': 0}]},
            'dataset': []
        },
        'expected_status': 'ok'
    },
    # Test key ordering: op first, then alphabetical
    {
        'name': 'Key ordering',
        'input': {
            'pipeline': {'steps': [{'op': 'map', 'expr': 'x', 'as': 'y'}]},
            'dataset': []
        },
        'expected_status': 'ok'
    },
]

for t in tests:
    input_raw = t.get('input_raw', json.dumps(t['input']))
    proc = subprocess.run(['python3', 'etl_pipeline.py'], input=input_raw, capture_output=True, text=True)
    result = json.loads(proc.stdout)

    passed = True
    if result.get('status') != t['expected_status']:
        passed = False
    if t.get('expected_code') and result.get('error_code') != t['expected_code']:
        passed = False

    status = 'PASS' if passed else 'FAIL'
    print(f'{status}: {t[\"name\"]}')
    if not passed:
        print(f'  Expected status: {t[\"expected_status\"]}, got: {result.get(\"status\")}')
        if t.get('expected_code'):
            print(f'  Expected code: {t[\"expected_code\"]}, got: {result.get(\"error_code\")}')
        print(f'  Output: {proc.stdout.strip()}')
    print()
"

